// Normalize the cal.com BOOKING_CREATED payload into flat fields.
const body = $input.first().json.body || {};
const p = body.payload || {};
const attendee = (p.attendees && p.attendees[0]) || {};
const link =
  (p.metadata && p.metadata.videoCallUrl) ||
  (p.videoCallData && p.videoCallData.url) ||
  (typeof p.location === 'string' && p.location.startsWith('http') ? p.location : '') ||
  ($env.CAL_WEBAPP_URL + '/booking/' + (p.uid || ''));
const fmt = (iso, tz) => {
  try {
    return new Intl.DateTimeFormat('en-US', {
      dateStyle: 'full', timeStyle: 'short', timeZone: tz || 'UTC',
    }).format(new Date(iso));
  } catch (e) { return iso || ''; }
};
return [{
  json: {
    triggerEvent: body.triggerEvent || '',
    title: p.title || 'Your call',
    attendeeName: attendee.name || 'there',
    attendeeEmail: attendee.email || '',
    organizerName: (p.organizer && p.organizer.name) || '',
    organizerEmail: (p.organizer && p.organizer.email) || '',
    when: fmt(p.startTime, attendee.timeZone),
    timeZone: attendee.timeZone || 'UTC',
    meetingLink: link,
    uid: p.uid || '',
  },
}];
